const { RTSPClient } = require\('yellowstone'\);

process.on\('uncaughtException', \(err\) => {
  if \(err.code === 'ECONNRESET'\) { console.warn\('Caught ECONNRESET'\); return; }
  console.error\('Uncaught:', err\);
}\);

const client = new RTSPClient\('admin', 'abcd1234'\);

// Early error handler
const poll = setInterval\(\(\) => {
  if \(client._client\) {
    clearInterval\(poll\);
    client._client.on\('error', \(e\) => console.warn\('Socket err caught:', e.code\)\);
  }
}, 50\);

client.connect\('rtsp://116.111.91.38:5555/Streaming/Channels/101', { connection: 'tcp' }\)
  .then\(d => {
    clearInterval\(poll\);
    console.log\('Connected! codec:', d.codec\);
    let cnt = 0;
    client.on\('data', \(ch, payload, pkt\) => {
      cnt++;
      if \(cnt <= 3\) console.log\('Frame', cnt, payload.length, 'bytes'\);
      if \(cnt === 10\) {
        console.log\('OK - 10 frames received'\);
        client.close\(true\).catch\(\(\)=>{}\);
        setTimeout\(\(\) => process.exit\(0\), 1000\);
      }
    }\);
    client.play\(\).then\(\(\) => console.log\('PLAY ok'\)\);
  }\)
  .catch\(e => console.error\('FAIL:', e.message\)\);
setTimeout\(\(\) => process.exit\(0\), 20000\);
